import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Reading a full line instead of next()

        char[] buffer = new char[10]; // buffer with fixed size

        // Copy user input into the buffer with bounds checking
        int length = Math.min(userInput.length(), buffer.length); // Ensure length does not exceed buffer size
        userInput.getChars(0, length, buffer, 0);

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
